// In your React component
const [input, setInput] = useState('');
const [reply, setReply] = useState('');
const [loading, setLoading] = useState(false);

async function handleSubmit(e) {
  e.preventDefault();
  setLoading(true);
  try {
    const res = await fetch('/api/chat', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ message: input })
    });
    const data = await res.json();
    setReply(data.reply);
  } finally {
    setLoading(false);
  }
}

return (
  <form onSubmit={handleSubmit}>
    <textarea value={input} onChange={e => setInput(e.target.value)} />
    <button disabled={loading}>{loading ? 'Thinking...' : 'Send'}</button>
    {reply && <p>{reply}</p>}
  </form>
);
```

### Two ways to return Claude's response

**Non-streaming (simpler):**
Wait for the full response, return it as JSON. Works fine for short responses or background tasks.

**Streaming (better UX):**
Send each word as it's generated using Server-Sent Events (SSE). The browser receives a stream of small chunks and renders them progressively.

The backend difference:
```js
// Non-streaming
const res = await client.messages.create({ /* ... */ });
res.json({ reply: res.content[0].text });

// Streaming  
const stream = client.messages.stream({ /* ... */ });
for await (const chunk of stream) {
  if (chunk.type === 'content_block_delta') {
    res.write(`data: ${chunk.delta.text}\n\n`);
  }
}
res.end();
```

```js
// Express streaming route
app.post('/api/stream', async (req, res) => {
  const { message, systemPrompt } = req.body;

  res.setHeader('Content-Type', 'text/event-stream');
  res.setHeader('Cache-Control', 'no-cache');
  res.setHeader('Connection', 'keep-alive');

  try {
    const stream = client.messages.stream({
      model: 'claude-3-haiku-20240307',
      max_tokens: 1000,
      system: systemPrompt ?? 'You are a helpful assistant.',
      messages: [{ role: 'user', content: message }]
    });

    for await (const chunk of stream) {
      if (chunk.type === 'content_block_delta' && chunk.delta.type === 'text_delta') {
        res.write(`data: ${JSON.stringify({ text: chunk.delta.text })}\n\n`);
      }
    }
    res.write('data: [DONE]\n\n');
  } catch (err) {
    res.write(`data: ${JSON.stringify({ error: err.message })}\n\n`);
  } finally {
    res.end();
  }
});
```

```jsx
const [output, setOutput] = useState('');

async function streamResponse(message) {
  setOutput('');
  const res = await fetch('/api/stream', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ message })
  });

  const reader = res.body.getReader();
  const decoder = new TextDecoder();

  while (true) {
    const { done, value } = await reader.read();
    if (done) break;
    const chunk = decoder.decode(value);
    const lines = chunk.split('\n').filter(l => l.startsWith('data: '));
    for (const line of lines) {
      const data = JSON.parse(line.slice(6));
      if (data === '[DONE]' || data.text === undefined) continue;
      setOutput(prev => prev + data.text);
    }
  }
}
```

